var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"옳지, 옳지. 배고팠구나?","JPN":"よしよし、お腹が空いているんだね？","ENG":"There, there. Who's a good kitty? You must've been hungry.","TWN":"乖，乖，你餓了吧？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"많이 줄 수는 없지만, 그래도 천천히 먹어~ 누가 뺏어가진 않으니까.","JPN":"これだけしかあげられないけど、ゆっくり食べるんだよ～取り上げる人は誰もいないから。","ENG":"It's not much, but you don't need to rush! No one's going to take it away from you.","TWN":"我只能給你這些，慢慢吃～不會有人跟你搶的。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_CAT_START"},{"id":"L7_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"배급 받은 분유라도 물에 타서 가져올 걸 그랬나? 밍밍하긴 해도 없는 것보단 나을 텐데.","JPN":"配給された粉ミルクでも水に溶かして持ってくればよかったかな？　味は薄いけど、ないよりはマシだったかも。","ENG":"Maybe I should've mixed up water with the ration formula. Not the best, but better than nothing.","TWN":"早知道就把分到的奶粉泡水裡拿過來，雖然口味淡一些，但有總比沒有好。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"그런데…… 고양이한테 과자나 우유를 줘도 됐던가?","JPN":"っていうか……猫ってお菓子とか牛乳をあげてもいいんだっけ？","ENG":"But... is it okay to give cats snacks or milk?","TWN":"不過……小貓可以吃餅乾或牛奶嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"에이~ 뭐, 아무렴 어때. 너도 배고픈 것보단 뭐라도 먹는 게 낫지?","JPN":"まぁいいか～、あなたもお腹を空かせてるぐらいなら、何でもいいから食べれる方がマシだよね？","ENG":"Oh, whatever. You'd prefer to eat something rather than starve, right, kitty?","TWN":"哎呀～隨便啦，有得吃總比餓肚子好吧？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"역시 여기 계셨군요. 시영 씨.","JPN":"やっぱりここにいたんですね。","ENG":"Just as I thought. You're here, Shiyoung.","TWN":"你果然在這裡，時雨。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L15_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"아차차~ 이를 어쩌나. 또 들켜버렸네요.","JPN":"あちゃ～参ったね。またバレちゃった。","ENG":"Oh boy. Well, you found me.","TWN":"哎呀呀～這可怎麼辦，又被你逮個正著。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"흥! 오늘은 얼렁뚱땅 넘어갈 생각하지 말아요, 시영 씨!","JPN":"フン！　今日は適当にあしらおうなんて思わないでくださいね、シノンさん！","ENG":"Hmph! You're not getting away that easy today, Shiyoung!","TWN":"哼！你今天可別想糊弄過去，時雨！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그 칼로리 블록은 생존자들을 위해 군에서 배급하는 소중한 식량이라고요.","JPN":"そのカロリーブロックは生存者のために、軍が支給する大事な食料なんです。","ENG":"That snack bar is a precious provision that the military provides to the survivors.","TWN":"那個營養口糧是軍隊分配給倖存者的珍貴糧食。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"사람이 먹을 식량도 부족한데 자꾸 그렇게 식량을 낭비하시면, 시영 씨의 몫을 줄일 수밖에 없다구요!","JPN":"人間ですら満足に食べられないというのに、そんなふうに食料を無駄遣いされてはシノンさんの分を減らすしかありませんよ！","ENG":"We don't even have enough for our people. If you keep wasting food like that, we'll have no choice but to give you less food!","TWN":"光是要給人吃就已經很吃緊，如果一直這麼浪費糧食，就只好減少你的分量！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"에이~ 소심도 하셔라.","JPN":"いやいや～ケチだなぁ。","ENG":"Jeez, so apprehensive.","TWN":"哎呀～真是小氣。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_PRIDE"}}}},{"id":"L20_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"자꾸 그렇게 깐깐하게 구니까, 카린 양이 다른 사람들한테 인기가 없는 거라고요.","JPN":"そんなにケチ臭いから、カリンさんはモテないんですよ。","ENG":"You won't get popular if you keep acting so fussy about things.","TWN":"卡琳你老是這麼計較，大家才不喜歡你。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"그렇지, 야옹아?","JPN":"ね？　猫ちゃん？","ENG":"Right, kitty?","TWN":"對吧，喵喵？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"히, 히익! 자, 잠깐! 고양이 들이밀지 마세요!","JPN":"ひ、ひいっ！　ちょ、ちょっと！　猫をこっちに押し付けないでください！","ENG":"E-eeek! S-stop! Get the cat away from me!","TWN":"嗚，嗚！走開！不要讓牠靠近我！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"네? 그렇지만 이렇게 귀여운 걸요? 한 번 쓰다듬어 볼래요, 카린 양?","JPN":"はい？　でもこんなにかわいいのに？　撫でてみません？　カリンさん？","ENG":"Huh? But it's so cute! You want to pet it, Karin?","TWN":"什麼？可是牠很可愛欸？你要不要摸一摸，卡琳？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그, 그게 아니라 전…… 에, 에, 엣!!","JPN":"い、いや、そうじゃなくて、私……は、は、はっ！！","ENG":"N-no, I-I-I'm... A-aah-aaaah–","TWN":"不，不要，我……哈，哈，哈！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"에, 엣―――취!!","JPN":"は、はくしょーーん！！","ENG":"A-ah-choo!","TWN":"哈——啾！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L29_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"전 고양이 털 알레르기가 있다고요!! 엣취!! 에에엣취!!","JPN":"私は猫アレルギーなんです！！　はくしょん！！　くしょん！！","ENG":"I'm allergic to cats! Achoo! Aaa-choo!","TWN":"我對貓毛過敏！哈啾！哈啾哈啾！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"아하하, 그래요?","JPN":"あはは、そうでした？","ENG":"Ah ha ha, is that so?","TWN":"哈哈，是喔？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"}}}},{"id":"L33_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"이거, 이거 또 생각지도 못한 귀여운 약점을 알아버렸네요. 카린 양?","JPN":"これはこれは、また予想外にかわいい弱点を見つけてしまったようですね。カリンさん？","ENG":"My, what an adorable weakness you have, Karin.","TWN":"哎呀呀，我又知道一個關於卡琳的可愛小弱點咧？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L34_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"야, 약점? 서, 설마!?","JPN":"じゃ、弱点？　ま、まさか！？","ENG":"W-weakness? N-no, you can't–","TWN":"弱，弱點？難，難道？！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L36_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"자아, 야옹아~ 저 군인 언니 따라 가면 맛있는 거 많이 먹을 수 있대.","JPN":"はい、猫ちゃん～！　あの軍人のお姉さんについていけば、美味しいものがたくさん食べられるらしいよ！","ENG":"Hey kitty, go follow that soldier for more treats.","TWN":"來，喵喵～去跟著那個軍人姊姊，她會給你很多好吃的。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"오늘은 저 군인 언니랑 놀아 볼까?","JPN":"今日はあのお姉さんに構ってもらおう？","ENG":"Let's hang out with her for the rest of the day!","TWN":"今天就和那個軍人姊姊玩吧？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"으앗!! 달라붙지 마! 달라붙지 말라고!! 에, 엣취!!","JPN":"きゃっ！！　くっつかないで！　くっつかないでったら！！　は、はっくしょん！！","ENG":"Ahhh! Don't come near me! Get away! A-ah-choo!","TWN":"啊啊！不要跟著我！走開走開！！哈，哈啾！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"}}}},{"id":"L42_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"아하하, 야옹이도 카린 양이 좋은 가봐요~ 다행이다!","JPN":"あはは、猫ちゃんもカリンさんを気に入ったみたいですね～よかったよかった！","ENG":"Ah ha ha, the kitty must like you too! How nice!","TWN":"哈哈，看來喵喵也很喜歡你呢～太好啦！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"시, 시영 씨!! 에, 에에, 엣―――취!!","JPN":"し、シノンさん！！　は、はぁ、はっくしょーん！！","ENG":"S-Shiyoung! A-a-ah-choo!","TWN":"時，時雨！哈，哈哈，哈——啾！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그, 그만 웃고 빨리 고양이 좀…… 엣취!! 떼 달라고요!!","JPN":"ちょ、ちょっと笑ってないで猫を……はくしょん！！　私から離してください！！","ENG":"S-stop laughing and get the cat–ah-choo!– off of me!","TWN":"別光顧著笑，快把貓……哈啾！帶走！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"흐음~ 글쎄요?","JPN":"ふーん～どうしようかな？","ENG":"Hmm... I don't know...","TWN":"嗯～怎麼辦呢？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_PRIDE"}}}},{"id":"L47_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"아시잖아요, 카린 양. 저는 보수 없이는 일 안 한다고요?","JPN":"ご存知ですよね、カリンさん。私は見返りのない仕事はしないんですが？","ENG":"As you're well aware, I don't work without getting paid.","TWN":"你也知道的，卡琳。我不做沒有報酬的事。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"옳지, 옳지. 잘했어~ 야옹아. 덕분에 까까 하나 더 먹겠네?","JPN":"よし、よし。よくやったね～猫ちゃん。おかげでお菓子をもらえたね。","ENG":"Aww, good job kitty. You deserve another treat!","TWN":"乖乖，好棒喔，這下又有零食到手囉？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"자, 이건 수고한 야옹이의 몫!","JPN":"はい、これは頑張ってくれた猫ちゃんの分！","ENG":"Here, this is for your hard work!","TWN":"來，這是給喵喵的！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L5_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"후후, 그렇게 맛있어?","JPN":"ふふ、そんなにおいしい？","ENG":"Heh heh, is it that tasty?","TWN":"呵呵，有那麼好吃嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_CAT_DAMAGE_DOWN"},{"id":"L8_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"야옹아, 알고 있니? 우리 세계는 멸망까지 얼마 남지 않았단다?","JPN":"ねぇ知ってる？　猫ちゃん。私たちの世界は滅亡まであともう少しなんだってさ。","ENG":"Hey kitty, did you know? This world is not too far from destruction.","TWN":"喵喵，你知道嗎？我們的世界就快要滅亡咧？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"카린 양이나, 다른 사람들은 어떻게든 그걸 막아보려고 열심히지만…….","JPN":"カリンさんや他のみんなが、なんとかそれを阻止しようと頑張っているけど……","ENG":"Karin and the others are trying their best to stop it, but...","TWN":"無論是卡琳，還是其他人，都想方設法要阻止滅亡……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"글쎄, 나는 잘 모르겠어.","JPN":"どうかな、私にはよくわからない。","ENG":"Well, I'm not sure.","TWN":"可是，我真不明白。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"간신히 얻어낸…… 소중한 시간이니까, 그 시간을 좀 더 의미 있게 보내야 하는 거 아닐까?","JPN":"命を懸けて手に入れた……大事な時間だから、その時間をもっと有意義に使うべきなんじゃないかな？","ENG":"We barely got this extra time, so... maybe we're supposed to spend it more wisely.","TWN":"這是好不容易才得到的……珍貴的時間，不是應該更有意義地度過嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"너는 어떻게 생각해, 야옹아?","JPN":"あなたはどう思う、猫ちゃん？","ENG":"What do you think, kitty?","TWN":"你怎麼想，喵喵？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"후후, 하긴 내가 괜한 걸 물었나?","JPN":"ふふ、そりゃそうか、変なこと聞いちゃったね。","ENG":"Heh heh, I guess it's a pointless question.","TWN":"呵呵，我是不是不該問你這些？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"우리 야옹이는 좋겠네~ 과자 하나로 아무 걱정없이 기뻐할 수 있고 말이야.","JPN":"猫ちゃんが羨ましいな～お菓子一つであんなに喜べるなんてさ。","ENG":"Must be nice to be a kitty, being able to enjoy a snack without a care in the world.","TWN":"當貓真好～只要一塊餅乾就可以很開心。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"나도 너처럼 아무 걱정 없이 살 수 있었으면 좋을 텐데.","JPN":"私もあなたみたいに、なんの心配もなしに生きられたいいのにな。","ENG":"I wish I could live like you, free from all worries.","TWN":"我也想像你這樣無憂無慮地生活呢。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"아얏! 갑자기 왜 손을 물고 그래?","JPN":"イタッ！　どうしたの、急に噛んできて！","ENG":"Aw! Did you just bite me?","TWN":"哎呀！幹嘛突然咬我的手？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_CAT_START"},{"id":"L23_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"응, 저건……?","JPN":"うん、あれは……？","ENG":"Oh, that's...?","TWN":"唔，那是……？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"아하, 기억났다! 이거 카린 양이 가지고 있었던 아티팩트잖아?","JPN":"あー、思い出した！　あれはカリンさんが持っていたアーティファクト？","ENG":"Aha! I remember! That's the Artifact that Karin had!","TWN":"喔喔，我想起來了！那是卡琳的人造神器吧？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"아까 야옹이 때문에 떨어트렸나보네?","JPN":"さっき猫に絡まれたとき落としたのかな？","ENG":"I guess she dropped it because of the kitty.","TWN":"是剛剛跟貓玩時落下的嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"흐음, 이름이 <color=#ffd34c>원숭이 손</color>이라고 했던가? 소원을 이뤄주는 아티팩트라고 했던 것 같은데…….","JPN":"ふむ、<color=#ffd34c>サルの手</color>っていう名前だったっけ？　願いを叶えてくれるアーティファクトだって言っていたような……","ENG":"Hmm, it was called the <color=#ffd34c>Monkey's Paw</color> or something. I think it's an Artifact that grants wishes...","TWN":"是叫<color=#ffd34c>猴爪</color>的東西？好像說是能實現人願望的人造神器……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_03"},{"id":"L27_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"그렇게 위험한 아티팩트라고 손도 못하게 하더니…….","JPN":"危険なアーティファクトだって触らせてもくれなかったくせに……","ENG":"She wouldn't even let me touch it, saying it was an extremely dangerous Artifact...","TWN":"她老說這個人造神器很危險，都不讓我碰……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"하여간, 꼼꼼해 보여도 은근 칠칠맞은 부분이 있다니까?","JPN":"まったく、几帳面なようで案外ドジなんだから。","ENG":"Oh well, she may seem meticulous but she's clumsier than you'd think.","TWN":"卡琳她看起來很嚴謹，但有時候又很冒失。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"어, 어라? 그런데 왜 케이스가 열려 있는 거지?","JPN":"あ、あれ？　でもなんでケースが開いているんだろう？","ENG":"Uh, wait. Why is the box open?","TWN":"嗯？盒子怎麼是打開的？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"떨어트린 충격으로 열렸나?","JPN":"落ちた衝撃で開いちゃったとか？","ENG":"Did it open when it hit the ground?","TWN":"是掉下來的時候打開的嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"설마, 이거 아티팩트가 발동한 거야?","JPN":"まさか、これアーティファクトが発動してる？","ENG":"Wait, did the Artifact activate?","TWN":"這個人造神器該不會已經啟動了吧？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"난 이렇다 할 소원을 빈 적이 없는데?","JPN":"願い事なんてした覚えないけどな？","ENG":"I didn't make a wish or anything.","TWN":"可是我沒有許願欸？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"야옹이는 좋겠네. 과자 하나로 아무 걱정없이 기뻐할 수 있고 말이야.","JPN":"猫ちゃんが羨ましいな～お菓子一つであんなに喜べるなんてさ。","ENG":"Must be nice to be a kitty, being able to enjoy a snack without a care in the world.","TWN":"當貓真好～只要一塊餅乾就可以很開心。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CROSSROAD","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"나도 너처럼 아무 걱정 없이 살 수 있었으면 좋을 텐데.","JPN":"私もあなたみたいに、なんの心配もなしに生きられたいいのにな。","ENG":"I wish I could live like you, free from all worries.","TWN":"我也想像你這樣無憂無慮地生活呢。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CROSSROAD","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"아, 아하하. 이거 곤란하네.","JPN":"あ、あはは。こりゃ参ったね。","ENG":"A-ah ha ha. This isn't good.","TWN":"哈，哈哈哈，這下糟糕啦。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"에이, 그냥 해본 말인데, 고작 이런 걸로 아티팩트가 발동한다고?","JPN":"いやいや、ポロっと出ただけの言葉に、アーティファクトが発動する？","ENG":"I mean, I wasn't serious, there's no way the Artifact would activate from that.","TWN":"哎呀，我只是說說而已，這樣就啟動啦？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"하아……. 카린 양한테 또 한소리 들으려나…….","JPN":"はぁ……カリンさんにまた怒られるかな……","ENG":"*Sigh...* Is Karin going to scold me again...?","TWN":"哀哀……卡琳又要念我了……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"에이, 모르겠다. 뭐, 어떻게든 되겠지. 그동안 한 두번 이런 것도 아니고…….","JPN":"まぁいいや。なんとかなるでしょ。こんなこと日常茶飯事なんだし……","ENG":"Oh, whatever. It's not like this is the first time I screwed up.","TWN":"就這樣吧，船到橋頭自然直，反正也不是第一次闖禍……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"설마, 죽기야 하겠어……?","JPN":"まさか、死にはしないよね……？","ENG":"It's not going to kill me or anything, right...?","TWN":"不至於要我的命吧……？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"(으으, 이 익숙한 멀미……. 또 차원간 이동을 한 걸까?)","JPN":"(うぅ、この馴染みのあるめまい……また次元間移動をしたのかな？)","ENG":"(Ngh, this motion sickness is familiar... Did I do an interdimensional jump again?)","TWN":"（唔唔，熟悉的眩暈感……是又在次元間移動嗎？）"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L7_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"(일단, 사지는 멀쩡히 붙어 있는 것 같은데……. 아니, 새끼발가락 쪽에 감각이 없는 것 같기도?)","JPN":"(とりあえず、手と足はちゃんとくっついてる……いや、足の小指に感覚がない？)","ENG":"(I think my limbs are all fine... but wait, I don't feel my pinky toes, I think.)","TWN":"（首先，四肢還健全……不對，腳的小拇指好像沒什麼感覺？）"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"하림 대장!! 구조 대상이 눈을 떴다, 정신을 차렸어!!","JPN":"ウサギ隊長！！　救助対処が目を覚ました、気が付いたんだ！！","ENG":"Captain Harim! The rescue target woke up! It's regained consciousness!","TWN":"夏琳隊長！救援對象睜開眼睛了，牠醒了！"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"정말? 다행이다!","JPN":"本当？　よかった！","ENG":"Really? I'm so relieved!","TWN":"真的嗎？太好了！"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"래빗센스에 잡힌 신호가 너무 희미해서 혹시나 싶었는데, 무시하지 않길 잘 했어!","JPN":"ラビットセンスが捉えた信号が弱すぎたから確信が持てなかったけど、スルーしなくてよかった！","ENG":"I wasn't sure because the signal I got from Rabbit Sense was too weak, but I'm glad I didn't ignore it!","TWN":"兔兔感應捕捉到的訊號太弱了，本來還不太確定，幸好沒有忽略掉訊號！"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"(구조대상……? 이 세계에서는 아이들도 구조 활동을 하나보네?)","JPN":"(救助対象……？　この世界では子どもも救助活動をするんだ？)","ENG":"(Rescue target? I guess children also engage in rescue activities in this world.)","TWN":"（救援對象……？這個世界小孩也要進行救援活動？）"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L14_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"(아하, 소원을 이뤄준다더니, 바캉스 때처럼 이 세계에서 푹 쉬고 오라는 뜻이려나?)","JPN":"(あ～、願いを叶えてくれるってのは、バカンスみたいにこの世界でゆっくり休めってことだったのかな？)","ENG":"(Aha, it grants wishes, so I guess this is its way of giving me an opportunity to relax in this world, like during vacation.)","TWN":"（唔……說是能讓人夢想成真，意思是會讓我像度假一樣在這個世界好好休息嗎？）"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"(후후, 예상치도 못한 휴가네. 이런 소원이라면 얼마든지 환영이지.)","JPN":"(ふふ、思いがけない休暇だ。こういう願いならいつでも大歓迎だよ。)","ENG":"(Heh heh, an unexpected treat. The wish turned out great.)","TWN":"（呼呼，是個意料之外的假期呢。這種願望求之不得！）"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"어허, 아직 움직이면 안 된다! 블랙 호크!","JPN":"こらっ、まだ動いてはならない！　ブラックホーク！","ENG":"Wait, you shouldn't move yet, Black Hawk!","TWN":"不行喔！現在還不能動，黑鷹！"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L19_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"블랙 호크라니. 또 그런 이상한 이름을 붙이면 어떡해, 소림아.","JPN":"ブラックホークって。ミズキったらまた変な名前を付けて。","ENG":"Black Hawk? You always give weird names to animals, Sorim.","TWN":"黑鷹？蕭林，你怎麼又取這麼奇怪的名字。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L20_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"그리고 이 아이…… 옷을 입고 있으니까, 주인이 있을 거야. 우리가 주인을 찾아줘야 해.","JPN":"それにこの子……服を着ているし、きっと飼い主がいるんだよ。僕たちが見つけてあげなきゃ。","ENG":"And this little one is wearing clothes, so it must have an owner. We have to find its owner.","TWN":"而且這孩子……還有穿衣服，所以應該是有主人的。我們幫牠找主人吧。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L21_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"(으음? 아이? 옷? 그리고 주인이라고……?)","JPN":"(ん？　この「子」？　服？　それに飼い主……？)","ENG":"(Hmm? Little one? Clothes? Owner...?)","TWN":"（嗯？孩子？衣服？還有主人……？）"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L22_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"(서, 설마 인신매매단……!? 이런 꼬맹이들이……!?)","JPN":"(ま、まさか人身売買集団……？　こんなちびちゃんたちが……！？)","ENG":"(A-are they human traffickers...?! These little kids...?!)","TWN":"（難，難道這些小鬼……？！……是人口販子？！）"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_HATE"},"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L23_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"(어쩌면 무시무시한 세계에 떨어진 걸지도 몰라.)","JPN":"(もしかすると、とんでもなく恐ろしい世界に飛ばされちゃったのかも。)","ENG":"(Maybe I've been transported to a very bleak world.)","TWN":"（說不定我掉入一個很可怕的世界。）"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L24_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"(어쨌든…… 어린애랑 싸우기는 싫으니까. 우선 대화부터……)","JPN":"(とにかく……子どもと戦うなんて嫌だから、まずは話し合ってみよう……)","ENG":"(Anyway... I don't want to fight children, so I'll talk first...)","TWN":"（總之……我不想和小孩子打起來，先試著和她們對話……）"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L27_1","type":"dialog","speaker":"JOOSHIYONG_CAT_NULL_NULL","text":{"KOREA":"냐오오옹!?","JPN":"にゃああ！？","ENG":"Meeow!?","TWN":"喵喵？！"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYONG_CAT_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_CAT_DAMAGE_DOWN"},{"id":"L28_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"(으으으응!?)","JPN":"(ええええっ！？)","ENG":"(Huuuh?!)","TWN":"（欸欸欸？！）"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_HATE"},"C":{"char_id":"JOOSHIYONG_CAT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"오오, 하림대장! 블랙 호크가 울부짖었다!","JPN":"おお、ウサギ隊長！　ブラックホークが泣き叫んだ！","ENG":"Ooh, Captain Harim! Black Hawk just spoke!","TWN":"哇喔，夏琳隊長！黑鷹叫咧！"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"잠, 잠깐! 고양이가 뭔가 하고 싶은 말이 있나 봐!","JPN":"ま、待って！　猫ちゃんが何か話したがってる！","ENG":"W-wait! The cat's trying to say something!","TWN":"等，等等！貓咪好像有什麼話要說！"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L34_1","type":"dialog","speaker":"JOOSHIYONG_CAT_NULL_NULL","text":{"KOREA":"냐옹!? 냐오옹, 냐옹.","JPN":"ミャオ！？　ミャオ、ミャオオ。","ENG":"Meow?! Meoow, meow.","TWN":"喵？！喵喵，喵。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYONG_CAT_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_CAT_DAMAGE_DOWN"},{"id":"L35_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"(뭐야?! 목소리가, 안 나와.)","JPN":"(何？！　声が、出せない。)","ENG":"(What?! My voice, it's not working.)","TWN":"（怎麼回事？！怎麼發不出聲音。）"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_HATE"},"C":{"char_id":"JOOSHIYONG_CAT_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L36_1","type":"dialog","speaker":"JOOSHIYONG_CAT_NULL_NULL","text":{"KOREA":"크르릉…… 냐오오옹!?","JPN":"ガルル……ミャオオ！？","ENG":"Grrrr... Meeeow?!","TWN":"呼嚕嚕……喵喵？！"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_HATE"},"C":{"char_id":"JOOSHIYONG_CAT_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_CAT_START"},{"id":"L37_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"(그리고…… 고양이라고!?)","JPN":"(それに……猫ちゃん！？)","ENG":"(Wait... Did they say \\"cat\\"?!)","TWN":"(而且……她們叫我貓咪？！）"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"JOOSHIYONG_CAT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"JOOSHIYONG_CAT_NULL_NULL","text":{"KOREA":"냐, 오옹……. 냐옹. 냐…… 나, 냐 야옹!?","JPN":"ニャ、ニャア……ニャア。ニャ……ニャアア！？","ENG":"M-meow... meow. Meow... m-meooow?!","TWN":"喵喵……喵。喵……喵，喵喵？！"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"JOOSHIYONG_CAT_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_CAT_DAMAGE_DOWN"},{"id":"L39_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"(아, 아하하…… 설마. 나…… 고양이가 되어버린 거야!?)","JPN":"(ア、アハハ……まさか。私……猫になっちゃった！？)","ENG":"(Ah ha ha... No way. Am I... a cat?!)","TWN":"（哈，哈哈哈……我該不會……變成貓啦？！）"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"JOOSHIYONG_CAT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"(아하, 하…… 하하, 이런…… 야단났네.)","JPN":"(アハ、ハ……ハハ、これは……大変だ。)","ENG":"(Ah ha, ha... ha ha... This... is concerning.)","TWN":"（哈哈，哈……哈哈……出事啦。）"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"JOOSHIYONG_CAT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};